class Solution {
public:
    bool digitCount(string num) {
        int count[10] = {0};
        for (char c : num) {
            count[c - '0']++;
        }
        for (int i = 0; i < num.size(); i++) {
            if (count[i] != num[i] - '0') {
                return false;
            }
        }
        return true;
    }
};
